import Foundation

extension QuestDatabase {

    static let microQuests: [QuestDefinition] = (0..<100).map { i in
        let template = microQuestTemplates[i]
        return QuestDefinition(
            id: "micro_\(String(format: "%03d", i + 1))",
            title: template.title,
            subtitle: template.subtitle,
            description: template.description,
            category: template.category,
            archetype: .interaction,
            difficulty: .easy,
            cadence: .daily,
            estimatedImpact: template.impact,
            estimatedTime: "Under 60 seconds",
            verification: .selfReport,
            baseXP: template.xp,
            scratchCardChance: 0.4,
            essenceReward: 2,
            steps: [QuestStep(id: "micro_\(String(format: "%03d", i + 1))_1", instruction: template.instruction, verification: .selfReport, xpReward: template.xp)],
            zone: template.zone
        )
    }

    private struct MicroTemplate {
        let title: String
        let subtitle: String
        let description: String
        let instruction: String
        let category: QuestCategory
        let impact: String
        let xp: Int
        let zone: QuestZone
    }

